INSERT INTO `practice_texts` VALUES (18,'Latihan 1','Jari Kelingking Kiri','aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz aqaz','id','general','easy',1,'2026-03-12 04:13:59'),(19,'Latihan 2','Jari Manis Kiri','swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx swsx','id','general','easy',1,'2026-03-12 04:14:43'),(20,'Latihan 3','','Pada fitur latihan mengetik saat ini, sistem penandaan kesalahan masih kurang efektif. Ketika pengguna mengetik huruf yang salah, huruf tersebut langsung ditandai dengan warna merah. Namun, kursor tetap melanjutkan ke huruf berikutnya tanpa memberikan kesempatan kepada pengguna untuk memperbaiki kesalahan tersebut. Akibatnya, kesalahan terus berlanjut dan menyebabkan banyak kata setelahnya ikut ditandai merah.\n\nKondisi ini membuat proses latihan menjadi kurang optimal karena pengguna tidak dapat dengan jelas mengetahui di bagian mana kesalahan sebenarnya terjadi. Selain itu, pengguna juga tidak terdorong untuk memperbaiki kesalahan secara langsung, sehingga tujuan latihan untuk meningkatkan akurasi mengetik menjadi kurang tercapai.','id','general','easy',1,'2026-03-12 15:19:16'),(21,'Latihan 4','asdf','asdf asdf adsf asdf asdf asdf asdf asdf asdf asdf asdf','id','general','easy',1,'2026-03-13 08:59:35'),(22,'a','a','a','id','general','easy',1,'2026-03-14 09:23:50'),(23,'b','b','b','id','general','easy',1,'2026-03-14 09:23:56'),(24,'c','c','c','id','general','easy',1,'2026-03-14 09:24:00'),(25,'d','d','d','id','general','easy',1,'2026-03-14 09:24:04'),(26,'e','e','e','id','general','easy',1,'2026-03-14 09:24:07'),(200,'P',NULL,'T','en','general','